#define BLOCK_SIZE 16

kernel void lud_diagonal(global float* a, local float* temp, const int size, const int offset)
{
    int i = get_global_id(0);
    int j, k;

    if (i >= BLOCK_SIZE) return;

    // Process row i of diagonal block - upper triangular part
    for (j = i; j < BLOCK_SIZE; j++) {
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += a[(offset + i) * size + (offset + k)] * a[(offset + k) * size + (offset + j)];
        }
        a[(offset + i) * size + (offset + j)] -= sum;
    }

    // Compute inverse of diagonal element
    float diag_val = a[(offset + i) * size + (offset + i)];
    float inv_diag = 1.0f / diag_val;

    // Process column i of diagonal block - lower triangular part
    for (j = i + 1; j < BLOCK_SIZE; j++) {
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += a[(offset + j) * size + (offset + k)] * a[(offset + k) * size + (offset + i)];
        }
        a[(offset + j) * size + (offset + i)] = (a[(offset + j) * size + (offset + i)] - sum) * inv_diag;
    }
}

kernel void lud_perimeter(global float* a, local float* temp_top, local float* temp_left, local float* temp_div, const int size, const int offset)
{
    int idx = get_global_id(0);
    int num_chunks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx >= BLOCK_SIZE * 2 * num_chunks) return;

    int is_right = idx < BLOCK_SIZE * num_chunks;
    int chunk_idx = idx % (BLOCK_SIZE * num_chunks) / BLOCK_SIZE;
    int elem_idx = idx % BLOCK_SIZE;

    if (is_right) {
        // Right perimeter: update elements to the right of diagonal block
        int j_global = offset + BLOCK_SIZE * (chunk_idx + 1);
        int i = elem_idx;

        // Load diagonal block row into local memory
        for (int k = 0; k < BLOCK_SIZE; k++) {
            temp_top[i * BLOCK_SIZE + k] = a[(offset + i) * size + (offset + k)];
        }

        float sum = 0.0f;
        for (int k = 0; k < i; k++) {
            sum += temp_top[i * BLOCK_SIZE + k] * a[(offset + k) * size + j_global + elem_idx];
        }
        a[(offset + i) * size + j_global + elem_idx] -= sum;
    } else {
        // Bottom perimeter: update elements below diagonal block
        int i_global = offset + BLOCK_SIZE * (chunk_idx + 1);
        int j = elem_idx;

        float sum = 0.0f;
        for (int k = 0; k < j; k++) {
            sum += a[(i_global + elem_idx) * size + (offset + k)] * a[(offset + k) * size + (offset + j)];
        }
        float diag = a[(offset + j) * size + (offset + j)];
        a[(i_global + elem_idx) * size + (offset + j)] = (a[(i_global + elem_idx) * size + (offset + j)] - sum) / diag;
    }
}

kernel void lud_internal(global float* a, local float* temp_top, local float* temp_left, const int size, const int offset)
{
    int idx_x = get_global_id(0);
    int idx_y = get_global_id(1);
    int num_chunks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx_x >= BLOCK_SIZE * num_chunks || idx_y >= BLOCK_SIZE * num_chunks) return;

    int chunk_x = idx_x / BLOCK_SIZE;
    int chunk_y = idx_y / BLOCK_SIZE;
    int i_local = idx_x % BLOCK_SIZE;
    int j_local = idx_y % BLOCK_SIZE;

    int i_global = offset + BLOCK_SIZE * (chunk_y + 1);
    int j_global = offset + BLOCK_SIZE * (chunk_x + 1);

    // Load temp data from diagonal block row and column
    for (int k = 0; k < BLOCK_SIZE; k++) {
        temp_top[i_local * BLOCK_SIZE + k] = a[(offset + i_local) * size + (j_global + k)];
        temp_left[i_local * BLOCK_SIZE + k] = a[(i_global + i_local) * size + (offset + k)];
    }

    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += temp_left[i_local * BLOCK_SIZE + k] * temp_top[k * BLOCK_SIZE + j_local];
    }

    a[(i_global + i_local) * size + (j_global + j_local)] -= sum;
}
